const response = $input.first().json;
const trashedFiles = response.files || [];

// If no trashed files, return nothing
if (trashedFiles.length === 0) {
  return [];
}

// Return each file as a separate item for processing
return trashedFiles.map(file => ({
  file_id: file.id,
  file_name: file.name,
  file_type: file.mimeType,
  file_url: file.webViewLink,
  trashed_time: file.trashedTime
}));

